changeSet.sql:
CREATE TABLE oauth_connect_requests (
                                        state VARCHAR(128) PRIMARY KEY,
                                        user_id BIGINT NOT NULL,
                                        provider VARCHAR(50) NOT NULL,
                                        expires_at TIMESTAMP NOT NULL,
                                        created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                                        CONSTRAINT fk_oauth_connect_user FOREIGN KEY (user_id) REFERENCES USERS(ID)
);

CREATE INDEX idx_oauth_connect_user_id ON oauth_connect_requests(user_id);
CREATE INDEX idx_oauth_connect_expires_at ON oauth_connect_requests(expires_at);
